"""因子研究 HTML 报告渲染器。"""

from __future__ import annotations

from pathlib import Path

import pandas as pd


def render_report(
    out_dir: Path,
    summary: pd.DataFrame,
    figure_map: dict[str, list[Path]],
    table_map: dict[str, list[Path]],
) -> Path:
    """生成轻量静态 HTML 报告（图表与表格链接）。"""
    rows = []
    rows.append("<h1>Stock Factor Research Report</h1>")
    rows.append(
        "<p>Generated by FactorLab pipeline. Includes IC, quantiles, turnover, diagnostics and significance.</p>"
    )

    rows.append("<h2>Summary</h2>")
    rows.append(summary.to_html(index=False, float_format=lambda x: f"{x:.4f}"))

    for section, figs in figure_map.items():
        rows.append(f"<h2>{section}</h2>")
        for fig in figs:
            rel = fig.relative_to(out_dir).as_posix()
            rows.append(f"<div><img src='{rel}' style='max-width:980px; width:100%;'/></div>")

    rows.append("<h2>Tables</h2>")
    for section, tables in table_map.items():
        rows.append(f"<h3>{section}</h3>")
        rows.append("<ul>")
        for t in tables:
            rel = t.relative_to(out_dir).as_posix()
            rows.append(f"<li><a href='{rel}'>{rel}</a></li>")
        rows.append("</ul>")

    # 追加数据适配器质量审计表（若存在）
    audit_dir = out_dir / "tables" / "data"
    if audit_dir.exists():
        audit_files = sorted(audit_dir.glob("*.csv"))
        if audit_files:
            rows.append("<h2>Data Adapter Audit</h2>")
            rows.append("<ul>")
            for t in audit_files:
                rel = t.relative_to(out_dir).as_posix()
                rows.append(f"<li><a href='{rel}'>{rel}</a></li>")
            rows.append("</ul>")

            summary_path = audit_dir / "adapter_quality_audit.csv"
            if summary_path.exists():
                summary = pd.read_csv(summary_path)
                rows.append("<h3>Adapter Quality Summary (Preview)</h3>")
                rows.append(summary.to_html(index=False))

    html = "\n".join(rows)
    out = out_dir / "index.html"
    out.write_text(html, encoding="utf-8")
    return out
